public struct MascotState {
    public var pose: Pose
    public var emotion: Emotion
    public var sinceIso: String
    public var bubbleText: String?

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(pose: Pose, emotion: Emotion, sinceIso: String, bubbleText: String?) {
        self.pose = pose
        self.emotion = emotion
        self.sinceIso = sinceIso
        self.bubbleText = bubbleText
    }
}



extension MascotState: Equatable, Hashable {
    public static func ==(lhs: MascotState, rhs: MascotState) -> Bool {
        if lhs.pose != rhs.pose {
            return false
        }
        if lhs.emotion != rhs.emotion {
            return false
        }
        if lhs.sinceIso != rhs.sinceIso {
            return false
        }
        if lhs.bubbleText != rhs.bubbleText {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(pose)
        hasher.combine(emotion)
        hasher.combine(sinceIso)
        hasher.combine(bubbleText)
    }
}


