public enum MascotEvent {
    
    case ruleFired(ruleName: String
    )
    case streakIncremented(name: String, count: UInt32
    )
    case streakReset(name: String
    )
    case creditEarned(amount: Int64
    )
    case bypassSpent(remaining: Int64
    )
    case penaltyEscalated(tier: String
    )
    case appLaunchedWhileBlocked(bundleId: String
    )
    case focusSessionStarted(minutes: UInt32
    )
